#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n, k; scanf("%d %d", &n, &k);
        long long *a = (long long*)malloc(n * sizeof(long long));
        for(int i=0;i<n;i++) scanf("%lld", &a[i]);
        if(n>0) k %= n; else k = 0;
        for(int i=0;i<n;i++){
            int idx = (k + i) % n; // element after rotation
            printf("%lld", a[idx]);
            if(i+1<n) printf(" ");
        }
        printf("\n");
        free(a);
    }
    return 0;
}

