#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); k = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        if n:
            k %= n
            rotated = arr[k:] + arr[:k]
        else:
            rotated = []
        out_lines.append(' '.join(map(str, rotated)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

